3_real_world_example.code:
const user = {};

// We define a property with specific rules
Object.defineProperty(user, 'id', {
  value: 999,
  writable: false,     // Cannot be changed
  enumerable: true,    // Shows up in loops
  configurable: false  // Cannot be deleted
});

console.log(user.id); // 999

//  Fails silently (or throws Error in strict mode)
user.id = 1000; 
console.log(user.id); // Still 999!

//  Cannot be deleted
delete user.id;
console.log(user.id); // Still 999!

